    def helper(
        n1: Optional['ListNode'], n2: Optional['ListNode'], carry: int
    ) -> Optional['ListNode']:
        if n1 is None and n2 is None and carry == 0:
            return None
        total = carry
        if n1:
            total += n1.val
            n1 = n1.next
        if n2:
            total += n2.val
            n2 = n2.next
        node = ListNode(total % 10)
        node.next = helper(n1, n2, total // 10)
        return node

    return helper(l1, l2, 0)

